;(function(){System.register([],function(exports,module){'use strict';return{execute:function(){((Drupal2,OVH2)=>{const headerUniverse={variables:{navbarIsOpened:false},constants:{switchDesktopDisplay:1200,buttonTogglerTextClose:OVH2.t("Close menu"),headerTogglerButtonText:document.querySelector("[data-header-button-text]")?.textContent},computed:{currentDisplay:"desktop"},elements:{main:document.querySelector(".ods-header-universe[data-header]"),ocms:document.querySelector("#block-ocms-topheader-menu"),navbar:document.querySelector("[data-navbar]"),overlay:document.querySelector("[data-header-overlay]"),topHeaderContainer:document.querySelector("[data-top-menu-container]"),mobileTopHeaderContainer:document.querySelector("[data-mobile-top-menu-container]"),topHeaderList:document.querySelector("[data-top-menu-list]"),topHeaderDomainSearch:document.querySelector(".ods-header-topbar [data-domain-wrapper]"),headerTogglerButton:document.querySelector("[data-header-toggler-button]"),headerTogglerButtonTextTag:document.querySelector("[data-header-button-text]"),topHeaderSubcategoryLinks:document.querySelectorAll("[data-top-menu-link-has-subcat], [data-language-switcher-btn]"),languageSwitcherContent:document.querySelector("[data-language-switcher-content]"),headerBackLinks:document.querySelectorAll("[data-back-link]"),shortBanner:document.querySelector("[data-short-banner]")},methods:{initialize:()=>{if(!headerUniverse.elements.main){console.log("Disable universe menu feature");return;}headerUniverse.methods.headerSizeToCSS();headerUniverse.events.clickTogglerButton();headerUniverse.events.clickOverlay();headerUniverse.events.clickBackLink();headerUniverse.events.focusSubcategoryLink();headerUniverse.events.clickSubcategoryLink();if(headerUniverse.elements.navbar){headerUniverse.events.windowSizeListener();}headerUniverse.methods.moveTopHeaderItems();headerUniverse.methods.showTopHeader();},showTopHeader:()=>{const removeHiddenClass=()=>{headerUniverse.elements.main?.querySelector(".language-switcher__wrapper")?.classList.remove("d-none");headerUniverse.elements.ocms?.querySelector(".language-switcher__wrapper")?.classList.remove("d-none");};if(document.readyState==="complete"){removeHiddenClass();}else{window.addEventListener("load",removeHiddenClass);}},navbarDisplay:()=>{if(headerUniverse.variables.navbarIsOpened){if(headerUniverse.methods.isMobile()){document.querySelector("body")?.classList.add("no-scroll");}headerUniverse.elements.navbar.classList.add("active");headerUniverse.elements.overlay.classList.remove("inactive");headerUniverse.elements.headerTogglerButton.classList.add("active");headerUniverse.elements.headerTogglerButtonTextTag.textContent=headerUniverse.constants.buttonTogglerTextClose;}else{document.querySelector("body")?.classList.remove("no-scroll");headerUniverse.elements.navbar.classList.remove("active");headerUniverse.elements.overlay.classList.add("inactive");headerUniverse.elements.headerTogglerButton.classList.remove("active");headerUniverse.elements.headerTogglerButtonTextTag.textContent=headerUniverse.constants.headerTogglerButtonText||null;}},isMobile:()=>{return window.innerWidth<headerUniverse.constants.switchDesktopDisplay;},menuSubcategoryDisplay:target=>{if(headerUniverse.methods.isMobile()){target.nextElementSibling?.classList.add("active");headerUniverse.elements.navbar.classList.add("no-scroll");const parentScrollLockMenu=target.closest("[data-menu-scroll-lock]");if(parentScrollLockMenu){parentScrollLockMenu.scroll({top:0,behavior:"smooth"});parentScrollLockMenu.classList.add("no-scroll");}}else{if(target.classList.contains("ods-navbar-link--n1")&&target.nextElementSibling?.querySelector("[data-menu-sublist]")){const childSubcategoryLinks=target.nextElementSibling.querySelectorAll("[data-link-has-subcat]");const childN3Lists=target.nextElementSibling.querySelectorAll("[data-menu-sublist]");[...childSubcategoryLinks].forEach(childSubcategoryLink=>{childSubcategoryLink.classList.remove("active");});[...childN3Lists].forEach(childN3List=>{childN3List.classList.remove("active");});childSubcategoryLinks[0].classList.add("active");childN3Lists[0].classList.add("active");target.nextElementSibling.style.minHeight=`${childN3Lists[0].offsetHeight}px`;}if(target.nextElementSibling?.classList.contains("ods-navbar__list--n3")){const siblingLinks=target.closest("[data-menu-sublist]")?.querySelectorAll("[data-link-has-subcat]");const siblingLists=target.closest("[data-menu-sublist]")?.querySelectorAll(".ods-navbar__list--n3");if(siblingLinks&&siblingLinks.length){[...siblingLinks].forEach(siblingLink=>{siblingLink.classList.remove("active");});}if(siblingLists&&siblingLists.length){[...siblingLists].forEach(siblingList=>{siblingList.classList.remove("active");});}target.setAttribute("aria-expanded","true");target.classList.add("active");target.nextElementSibling.classList.add("active");const navBarList2=target.closest(".ods-navbar__list--n2");if(navBarList2){navBarList2.style.minHeight=`${target.nextElementSibling.offsetHeight}px`;target.nextElementSibling.style.minHeight=`${navBarList2.offsetHeight}px`;}}}},closeHeaderSubsMenu:()=>{document.querySelectorAll('[data-top-menu-link-has-subcat][aria-expanded="true"], [data-language-switcher-btn][aria-expanded="true"]').forEach(expandedLink=>{expandedLink.setAttribute("aria-expanded","false");});},moveTopHeaderItems:()=>{if(headerUniverse.methods.isMobile()){if(headerUniverse.computed.currentDisplay==="mobile"){return;}if(headerUniverse.elements.topHeaderDomainSearch){headerUniverse.elements.mobileTopHeaderContainer.appendChild(headerUniverse.elements.topHeaderDomainSearch);}if(headerUniverse.elements.topHeaderList){headerUniverse.elements.mobileTopHeaderContainer.appendChild(headerUniverse.elements.topHeaderList);headerUniverse.elements.topHeaderList.classList.remove("d-none");}headerUniverse.computed.currentDisplay="mobile";}else{if(headerUniverse.computed.currentDisplay==="desktop"){return;}headerUniverse.variables.navbarIsOpened=false;headerUniverse.methods.navbarDisplay();if(headerUniverse.elements.topHeaderDomainSearch&&headerUniverse.elements.topHeaderDomainSearch.parentNode!==headerUniverse.elements.topHeaderContainer){headerUniverse.elements.topHeaderContainer.appendChild(headerUniverse.elements.topHeaderDomainSearch);}if(headerUniverse.elements.topHeaderList&&headerUniverse.elements.topHeaderList.parentNode!==headerUniverse.elements.topHeaderContainer){headerUniverse.elements.topHeaderContainer.appendChild(headerUniverse.elements.topHeaderList);}headerUniverse.computed.currentDisplay="desktop";}},showOverlayDesktop:()=>{if(!headerUniverse.methods.isMobile()){headerUniverse.elements.overlay.classList.remove("inactive");}},hideOverlayDesktop:()=>{if(!headerUniverse.methods.isMobile()){headerUniverse.elements.overlay.classList.add("inactive");}},headerSizeToCSS:()=>{const headerHeight=headerUniverse.elements.main.offsetHeight;const shortBannerHeight=headerUniverse.elements.shortBanner?.offsetHeight||0;document.documentElement.style.setProperty("--ovh-header-height",`${headerHeight+shortBannerHeight}px`);}},events:{clickTogglerButton:()=>{headerUniverse.elements.headerTogglerButton?.addEventListener("click",()=>{headerUniverse.variables.navbarIsOpened=!headerUniverse.variables.navbarIsOpened;headerUniverse.methods.navbarDisplay();});},clickOverlay:()=>{const{overlay}=headerUniverse.elements;overlay.addEventListener("click",()=>{overlay.classList.add("inactive");headerUniverse.variables.navbarIsOpened=false;headerUniverse.methods.navbarDisplay();});},clickSubcategoryLink:()=>{[...headerUniverse.elements.topHeaderSubcategoryLinks].forEach(subcategoryLink=>{subcategoryLink.addEventListener("click",evt=>{headerUniverse.methods.menuSubcategoryDisplay(subcategoryLink);if(headerUniverse.methods.isMobile()){evt.preventDefault();evt.stopPropagation();evt.stopImmediatePropagation();}});});},focusSubcategoryLink:()=>{const{topHeaderSubcategoryLinks}=headerUniverse.elements;[...topHeaderSubcategoryLinks].forEach(subcategoryLink=>{if(!headerUniverse.methods.isMobile()){subcategoryLink.closest("li")?.addEventListener("mouseenter",()=>{subcategoryLink.setAttribute("aria-expanded","true");});subcategoryLink.closest("li")?.addEventListener("mouseleave",()=>{subcategoryLink.setAttribute("aria-expanded","false");});}});},// Go back to previous menu level
clickBackLink:()=>{[...headerUniverse.elements.headerBackLinks].forEach(backLink=>{if(headerUniverse.methods.isMobile()){backLink.addEventListener("click",()=>{backLink.closest("[data-menu-scroll-lock]")?.classList.remove("no-scroll");const parentNode=backLink.parentNode;if(parentNode&&parentNode.closest("[data-menu-sublist]")){parentNode.closest("[data-menu-sublist]")?.classList.remove("active");}else if(parentNode.parentElement.hasAttribute("data-language-switcher-content")){parentNode.parentElement.classList.remove("active");}if(backLink.closest("[data-menu-sublist]")&&backLink.closest("[data-menu-sublist]")?.classList.contains("ods-navbar__list--n2")){headerUniverse.elements.navbar.classList.remove("no-scroll");}});}});},windowSizeListener:()=>{window.addEventListener("resize",Drupal2.debounce(()=>{headerUniverse.methods.moveTopHeaderItems();headerUniverse.methods.headerSizeToCSS();},200));}},attach:()=>{headerUniverse.methods.showTopHeader();headerUniverse.methods.initialize();}};Drupal2.behaviors.headerUniverse=headerUniverse;})(Drupal,OVH);}};});})();
